--
-- Name: anchor_view_invoice_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.anchor_view_invoice_summary AS
 SELECT inv.uid AS invoice_id,
    inv.invoice_number,
    inv.inv_date,
    inv.due_date,
    c.client_name AS bill_to_client,
    u.username AS created_by_user,
    inv.inv_total,
    inv.status,
        CASE
            WHEN (inv.status ~~* 'paid'::text) THEN 'Paid'::text
            WHEN (inv.due_date < CURRENT_DATE) THEN 'Overdue'::text
            ELSE 'Pending'::text
        END AS payment_status
   FROM ((public.anchor_invoices inv
     LEFT JOIN public.anchor_clients c ON ((TRIM(BOTH FROM lower((inv.bill_to)::text)) = TRIM(BOTH FROM lower(c.client_name)))))
     LEFT JOIN public.anchor_users u ON ((inv.created_by = u.id)));


ALTER VIEW public.anchor_view_invoice_summary OWNER TO postgres;

--
-- Name: anchor_view_revenue_by_client; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.anchor_view_revenue_by_client AS
 SELECT c.id AS client_id,
    c.client_name,
    count(DISTINCT inv.uid) AS total_invoices,
    sum(inv.inv_total) AS total_revenue,
    min(inv.inv_date) AS first_invoice_date,
    max(inv.inv_date) AS last_invoice_date
   FROM (public.anchor_clients c
     LEFT JOIN public.anchor_invoices inv ON ((TRIM(BOTH FROM lower((inv.bill_to)::text)) = TRIM(BOTH FROM lower(c.client_name)))))
  GROUP BY c.id, c.client_name
  ORDER BY (sum(inv.inv_total)) DESC;


ALTER VIEW public.anchor_view_revenue_by_client OWNER TO postgres;

--
-- Name: anchor_view_timesheet_detailed; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.anchor_view_timesheet_detailed AS
 SELECT e.id,
    e.entry_date,
    COALESCE(c.client_name, '—'::text) AS client_name,
    e.client,
    e.activity,
    e.service,
    e.status,
    e.retainer,
    e.bill_to_client,
    e.standard_fee,
    e.rate,
    e.hours,
    (COALESCE(e.total, (e.rate * e.hours), (0)::numeric))::numeric(12,2) AS amount,
    e.comments,
    e."user" AS user_id,
    COALESCE(u.username, '—'::text) AS username,
    u.email AS user_email,
    e.inv_id,
    (e.inv_id IS NOT NULL) AS is_billed
   FROM ((public.anchor_timesheet_entries e
     LEFT JOIN public.anchor_clients c ON ((c.id = e.client)))
     LEFT JOIN public.anchor_users u ON ((u.id = e."user")));


ALTER VIEW public.anchor_view_timesheet_detailed OWNER TO postgres;

--
-- Name: anchor_view_timesheet_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.anchor_view_timesheet_summary AS
 SELECT t.id AS timesheet_id,
    t.timesheet_number,
    t.created_date,
    u.username AS user_name,
    u.email AS user_email,
    t.total_hours,
    count(te.id) AS entry_count,
    sum(te.total) AS total_billable_amount
   FROM ((public.anchor_daily_timesheets t
     LEFT JOIN public.anchor_users u ON ((t.user_id = u.id)))
     LEFT JOIN public.anchor_timesheet_entries te ON (((te."user" = u.id) AND (te.entry_date = t.created_date))))
  GROUP BY t.id, t.timesheet_number, t.created_date, u.username, u.email, t.total_hours;


ALTER VIEW public.anchor_view_timesheet_summary OWNER TO postgres;

